import Chats from "./pages/chats";
import signup from "./components/Authentication/signup";

function App() {
  return (
    <div className="App">
      <Route path="/" component={Home} exact/>
      {/* <Route paht="/signup" component = {signup} exact/> */}
      <Route path="/chats" component={Chats} exact />
    </div>
  );
}

export default App;
